noncompliant:
// Noncompliant: Backward jump to earlier label
void function() {
label1:
    printf("Start");
    int x = 10;
    if (x > 5) {
        goto label1; // Backward jump - creates loop
    }
}

compliant:
// Compliant: Forward jump to later label
void function() {
    int x = getValue();
    if (x < 0) {
        goto error_cleanup; // Forward jump
    }
    processValue(x);
    return;

error_cleanup:
    logError("Invalid value");
    cleanup();
}
